try:
    new_notebook_feature_flag = df_feature_flags.where("FlagName = 'nemde_flag'").collect()[0]["FlagState"]
except Exception as e:
    print(e) # printing error output in case unexpected errors occur with the above

if new_notebook_feature_flag:
    print("Feature flag is configured for this notebook")    
else:
    # Feature flag doesn't exist, so this section runs by default. The below kill command stops the Notebook from running. 
    print("Feature Flag for this notebook is not configured or not in the True state.")
    mssparkutils.notebook.exit("Feature is not Production-ready. Closing Notebook.")

#Silver load dates
df_Latest_LoadDate = spark.sql(f"""
                        SELECT date_format(CDCLoadDate,'yyyy-MM-dd HH:mm:ss.SSSSSS') AS Latest_LoadDate FROM
                            (SELECT DISTINCT CDCLoadDate FROM {lake_db_name}.{db_tablename}
                            ORDER BY CDCLoadDate DESC
                            LIMIT 1);
                    """)
#display(df_Latest_LoadDate)

if df_Latest_LoadDate.count() > 0 and df_Latest_LoadDate.collect()[0][0] != None:
    silver_loaddate = df_Latest_LoadDate.collect()[0][0]

else:
    silver_loaddate = '1900-01-01 00:00:00.000000'
print(silver_loaddate)
